define float @fmul_by_self_if_0_oeq_zero_f32(float %x) {
  %x.is.zero = fcmp oeq float %x, 0.000000e+00
  %scaled.x = fmul float %x, %x
  %scaled.if.denormal = select nnan i1 %x.is.zero, float %scaled.x, float %x
